namespace sv_c90496ad9838460e8a1a2e632e748cb5.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella and basil.", 25),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with pancetta and pecorino.", 20),
            new(3, "Tiramisu", "Layered coffee-flavoured Italian dessert.", 40),
        },
        [2] = new List<Recipe>
        {
            new(4, "Sushi Rolls", "Fresh fish and rice wrapped in nori seaweed.", 45),
            new(5, "Ramen", "Rich pork broth noodle soup with soft-boiled egg.", 60),
            new(6, "Tempura", "Lightly battered and fried vegetables and shrimp.", 30),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-grilled pork tacos with pineapple and cilantro.", 35),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Enchiladas", "Corn tortillas rolled with chicken and smothered in salsa.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_recipes.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_c90496ad9838460e8a1a2e632e748cb5.Services
@using Microsoft.AspNetCore.Components
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h3>Recipes for Cuisine @CuisineId</h3>

<div class="mb-3">
    <label class="me-2">Sort:</label>
    <a href="@GetSortUrl("newest")" class="btn btn-sm @(Sort == "newest" ? "btn-primary" : "btn-outline-primary") me-1">Newest</a>
    <a href="@GetSortUrl("popular")" class="btn btn-sm @(Sort == "popular" ? "btn-primary" : "btn-outline-primary")">Popular</a>
</div>

@if (_errorKind == ErrorKind.Timeout)
{
    <div class="alert alert-warning">
        <p>The request timed out. Please try again.</p>
        <button class="btn btn-outline-warning btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_errorKind == ErrorKind.General)
{
    <div class="alert alert-danger">
        <p>Something went wrong while loading recipes. Please try again.</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <div class="text-muted">
        <p><em>Loading recipes…</em></p>
    </div>
}
else
{
    @if (_isRefreshing)
    {
        <div class="text-info mb-2"><small>Refreshing…</small></div>
    }

    <ul class="list-group">
        @foreach (var recipe in GetSortedRecipes())
        {
            <li class="list-group-item">
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="badge bg-secondary ms-2">@recipe.PrepTimeMinutes min</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private ErrorKind? _errorKind;

    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private enum ErrorKind { Timeout, General }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload if the cuisine changed
        if (CuisineId == _loadedCuisineId && _errorKind is null)
            return;

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        CancelPending();

        _errorKind = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against stale completions after a new request was started
            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // We cancelled this ourselves (new cuisine or dispose) — do nothing
        }
        catch (OperationCanceledException ex)
        {
            // Cancelled externally or timed out
            Logger.LogWarning(ex, "Recipe loading for cuisine {CuisineId} timed out or was cancelled externally.", CuisineId);
            _isRefreshing = false;
            _errorKind = ErrorKind.Timeout;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}.", CuisineId);
            _isRefreshing = false;
            _errorKind = ErrorKind.General;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes.OrderByDescending(r => r.PrepTimeMinutes),
            _ => _recipes.OrderByDescending(r => r.Id),
        };
    }

    private string GetSortUrl(string sort)
    {
        return $"/recipes/{CuisineId}?sort={sort}";
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

